using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for inline combinations ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(25.00, 2, 0.10, 55.00, DisplayName = "Two items, 10% tax")]
    [DataRow(99.99, 3, 0.08, 323.97, DisplayName = "Three items, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(50.00, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithVariousInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, Math.Round(result, 2));
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative price throws")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity throws")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below 0")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_WithInvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for richer scenarios ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithVariousDiscounts_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 0m, 100m),
        (100m, 10m, 90m),
        (100m, 25m, 75m),
        (100m, 50m, 50m),
        (100m, 100m, 0m),
        (200m, 15m, 170m),
        (0m, 50m, 0m),
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountTestData))]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> InvalidDiscountTestData =>
    [
        (100m, -1m),
        (100m, 101m),
        (50m, -0.01m),
        (50m, 100.01m),
    ];

    // --- FormatPrice: DataRow for string output verification ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default USD")]
    [DataRow(1234.50, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(9.9, "£", "£9.90", DisplayName = "Pads to two decimals")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

